class Solution:
    def arraySign(self, nums):
        product = 1
        for x in nums:
            product *= x
        if product > 0:
            return 1
        if product < 0:
            return -1
        return 0

solutions.python:
class Solution:
    def arraySign(self, nums):
        neg = 0
        for x in nums:
            if x == 0:
                return 0
            if x < 0:
                neg += 1
        return 1 if neg % 2 == 0 else -1

